import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  DEFAULT_THEME_ID,
  getTheme,
  listThemes,
  type Theme,
} from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:theme";

// Theme ids that should enable the `.dark` CSS class for Tailwind dark utilities.
const DARK_THEME_IDS = new Set(["t3-dark", "t3-midnight"]);

let listeners: Array<() => void> = [];
let lastSnapshot: { themeId: string } | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredThemeId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  // Accept only known theme ids; fall back to default for legacy values
  // ("light", "dark", "system") or unknown values.
  if (raw && getTheme(raw).id === raw) return raw;
  return DEFAULT_THEME_ID;
}

function applyTheme(themeId: string, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const theme = getTheme(themeId);
  const el = document.documentElement;

  // Apply core color overrides via inline CSS custom properties.
  // Inline styles take precedence over all :root rules in index.css.
  el.style.setProperty("--background", theme.colors.background);
  el.style.setProperty("--foreground", theme.colors.foreground);
  el.style.setProperty("--primary", theme.colors.accent);
  el.style.setProperty("--ring", theme.colors.accent);

  // Theme-specific custom properties used by sidebar, editor, terminal, status bar.
  el.style.setProperty("--t3-sidebar", theme.colors.sidebar);
  el.style.setProperty("--t3-editor", theme.colors.editor);
  el.style.setProperty("--t3-terminal", theme.colors.terminal);
  el.style.setProperty("--t3-statusbar", theme.colors.statusBar);

  // Font customisation.
  el.style.setProperty("--font-family", theme.fontFamily);
  el.style.setProperty("--font-size", `${theme.fontSize}px`);

  // Toggle Tailwind dark-mode class so dark: utilities and @variant dark rules work.
  el.classList.toggle("dark", DARK_THEME_IDS.has(themeId));

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash.
applyTheme(getStoredThemeId());

function getSnapshot(): { themeId: string } {
  const themeId = getStoredThemeId();

  if (lastSnapshot && lastSnapshot.themeId === themeId) {
    return lastSnapshot;
  }

  lastSnapshot = { themeId };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs.
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStoredThemeId(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const themeId = snapshot.themeId;
  const theme: Theme = getTheme(themeId);
  const availableThemes = listThemes();
  const resolvedTheme: "light" | "dark" = DARK_THEME_IDS.has(themeId) ? "dark" : "light";

  const setTheme = useCallback((id: string) => {
    localStorage.setItem(STORAGE_KEY, id);
    applyTheme(id, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change.
  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  return { theme, setTheme, availableThemes, resolvedTheme } as const;
}

