            )}
            onClick={() => setTheme(t.id)}
          >
            {/* Three-color swatch strip: background / sidebar / accent */}
            <div
              className="flex shrink-0 overflow-hidden rounded"
              aria-hidden="true"
            >
              <div className="h-6 w-4" style={{ background: t.colors.background }} />
              <div className="h-6 w-4" style={{ background: t.colors.sidebar }} />
              <div className="h-6 w-4" style={{ background: t.colors.accent }} />
            </div>

            <span className="flex-1 text-sm font-medium">{t.name}</span>

            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

