export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

export const DEFAULT_THEME_ID = "t3-dark";

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0a0a0f",
      foreground: "#e2e8f0",
      accent: "#7c3aed",
      sidebar: "#111118",
      editor: "#0f0f17",
      terminal: "#080810",
      statusBar: "#1a1a2e",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#1e293b",
      accent: "#6d28d9",
      sidebar: "#f8fafc",
      editor: "#ffffff",
      terminal: "#f1f5f9",
      statusBar: "#f1f5f9",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#020209",
      foreground: "#c8d3e6",
      accent: "#818cf8",
      sidebar: "#060612",
      editor: "#030310",
      terminal: "#020207",
      statusBar: "#0a0a1f",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
];

const THEMES_BY_ID = new Map<string, Theme>(
  BUILT_IN_THEMES.map((theme) => [theme.id, theme]),
);

export function getTheme(id: string): Theme {
  return THEMES_BY_ID.get(id) ?? (THEMES_BY_ID.get(DEFAULT_THEME_ID) as Theme);
}

export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

